const handleRazorpayPayment = async (orderData) => {

  console.log("RAZORPAY ORDER DATA:", orderData);

  const loaded = await loadRazorpayScript();

  if (!loaded) {
    toast.error('Razorpay SDK failed to load');
    return;
  }

  if (
    !orderData ||
    !orderData.razorpayOrderId ||
    !orderData.amount ||
    !orderData.currency ||
    !orderData.keyId
  ) {
    console.error("INVALID RAZORPAY DATA:", orderData);
    toast.error("Invalid Razorpay response");
    return;
  }

  const options = {
    key: String(orderData.keyId),

    amount: Number(orderData.amount),

    currency: String(orderData.currency),

    name: 'BRANDS HUB',

    description: `Order #${orderData.order.orderNumber}`,

    order_id: String(orderData.razorpayOrderId),

    handler: async (response) => {

      console.log("PAYMENT SUCCESS:", response);

      try {

        await orderAPI.verifyPayment({
          razorpayOrderId: response.razorpay_order_id,
          razorpayPaymentId: response.razorpay_payment_id,
          razorpaySignature: response.razorpay_signature,
          orderId: orderData.order.id,
        });

        await clearCart();

        toast.success('Payment successful!');

        navigate(`/orders/${orderData.order.id}`);

      } catch (err) {

        console.error("VERIFY PAYMENT ERROR:", err);

        toast.error('Payment verification failed');
      }
    },

    prefill: {
      name: form.fullName,
      contact: form.phone,
    },

    theme: {
      color: '#FFD600',
    },

    modal: {
      ondismiss: () => {
        toast('Payment cancelled', { icon: 'ℹ️' });
      },
    },
  };

  console.log("RAZORPAY OPTIONS:", options);

  const rzp = new window.Razorpay(options);

  rzp.open();
};

const handleSubmit = async (e) => {

  e.preventDefault();

  if (
    !form.fullName ||
    !form.phone ||
    !form.address ||
    !form.city ||
    !form.pincode
  ) {
    toast.error('Please fill all fields');
    return;
  }

  setLoading(true);

  try {

    const res = await orderAPI.checkout({
      ...form,
      paymentMethod,
    });

    console.log("CHECKOUT RESPONSE:", res.data);

    const data = res.data.data;

    if (paymentMethod === 'RAZORPAY') {

      if (
        !data ||
        !data.razorpayOrderId ||
        !data.amount ||
        !data.currency ||
        !data.keyId
      ) {
        toast.error("Invalid Razorpay order data");
        console.error("BAD DATA:", data);
        return;
      }

      await handleRazorpayPayment(data);

    } else {

      await clearCart();

      toast.success('Order placed successfully!');

      navigate(`/orders/${data.id}`);
    }

  } catch (err) {

    console.error("CHECKOUT ERROR:", err);

    toast.error(
      err.response?.data?.message ||
      'Failed to place order'
    );

  } finally {

    setLoading(false);
  }
};
